/**
 * Functional E2E tests for Enhanced Resources UI-PKG-001 (MarbleForm Main Window Shell).
 *
 * Generated by ui-test-writer for the RED phase of phase-3-ui implementation. All tests use
 * `test()` — bodies are complete but skipped until the component-builder activates them by
 * replacing `test(` with `test(`.
 *
 * Coverage:
 *
 * - Test scenarios: TS-043, TS-044, TS-045, TS-048, TS-049, TS-050, TS-051, TS-052, TS-053, TS-055,
 *   TS-076, TS-077.
 * - Behaviors: BHV-305, BHV-306, BHV-308, BHV-310, BHV-317, BHV-319, BHV-600, BHV-601, BHV-613,
 *   BHV-616.
 * - Evidence points: EVD-001 .. EVD-007 (see ui-spec-marble-form.md Test Contract section).
 *
 * Forward notes incorporated:
 *
 * - FN-013 (wg-marker spike): scripture pane render assertions verify wg-annotated tokens render as
 *   clickable elements without console errors.
 * - FN-015 (BCV control wiring): asserts the BCV reference button in the top toolbar exposes a
 *   clickable interactive control (real `useWebViewScrollGroupScrRef` wiring is out of scope for
 *   storybook-design but mandatory in phase-3-ui).
 * - FN-016 (highlight + info-icon command registration): asserts the "All Research Terms" toggle and
 *   the info-icon button dispatch their registered commands.
 * - FN-017 (H/G display-mode controls in hamburger menu): validation tests for the hamburger radio
 *   groups instead of a visible header row.
 * - FN-020 (integrated webview state machine): cross-component tests for word-overlay propagation,
 *   tab-switch propagation, and clear-filter sync across panes.
 * - FN-024 (toolbar responsive shrinking, space-based): edge-case test for narrow-width tab bar where
 *   labels collapse to icon-only.
 *
 * Frame: WebView content is hosted in `iframe[title="Enhanced Resource"]` per Test Contract.
 */
import { test, expect } from '../../fixtures/cdp.fixture';
import { waitForAppReady } from '../../fixtures/helpers';
import { closeAllNonHomeDockTabs, openEnhancedResource } from './test-helpers';

// ────────────────────────────────────────────────────────────────────────────────────────────────
// Constants pulled from the Test Contract (ui-spec-marble-form.md, lines 562-586) and the
// platform-enhanced-resources contributions. Update here if the contract changes.
// ────────────────────────────────────────────────────────────────────────────────────────────────

/** WebView frame selector (Test Contract — WebView Frame Selector). */
const ER_FRAME_SELECTOR = 'iframe[title="Enhanced Resource"]';

/**
 * Top-level menu the launcher (UI-PKG-009) registers under — Platform.Bible's main menu is
 * "Platform".
 */
const APP_MENU_NAME = /^Platform$/i;

/**
 * Localized label for the launcher menu item. Matches just "Open Enhanced Resource" exactly to
 * avoid picking up "Open..." or "Open Dictionary: SDBH/SDBG" siblings.
 */
const ER_MENU_ITEM_NAME = /^Open Enhanced Resource$/i;

/** Dock tab label fragment for the opened ER window. */
const ER_DOCK_TAB = /Enhanced Resource/i;

/**
 * Screenshot path convention from Test Contract:
 * `proofs/component-evidence/WP-001/{EVD}-{slug}.png`.
 */
const EVIDENCE_DIR = 'proofs/component-evidence/UI-PKG-001';

// ────────────────────────────────────────────────────────────────────────────────────────────────

test.describe('Enhanced Resources Functional Tests (UI-PKG-001 — MarbleForm)', () => {
  test.beforeEach(async ({ mainPage }) => {
    await closeAllNonHomeDockTabs(mainPage);
  });

  // ════════════════════════════════════════════════════════════════════════════════════════════
  // Category 1: Navigation
  // ════════════════════════════════════════════════════════════════════════════════════════════

  // @scenario TS-044
  // Behaviors: BHV-616 (window creation/reuse). Covers the happy path: open ER from menu, dock
  // tab appears, WebView frame is reachable.
  test('should open Enhanced Resource window via Platform.bible menu', async ({ mainPage }) => {
    await waitForAppReady(mainPage);

    // EVD-001a (intermediate): open the top-level menu so the launcher item is visible.
    await mainPage.getByRole('menuitem', { name: APP_MENU_NAME }).click();
    await mainPage.screenshot({ path: `${EVIDENCE_DIR}/EVD-001a-menu-open.png` });
    await mainPage.keyboard.press('Escape');

    // Open ER via the launcher (helper handles the auto-shown MarbleGuide on first session open).
    await openEnhancedResource(mainPage);

    // Verify the WebView iframe rendered the scripture pane.
    const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
    await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

    // EVD-001: ER window fully loaded — scripture pane visible, dictionary tab active.
    await mainPage.screenshot({ path: `${EVIDENCE_DIR}/EVD-001-window-loaded.png` });
  });

  // @scenario TS-043
  // Behaviors: BHV-616 + INV-011 (non-Marble guard). The launcher must reject a request to open
  // the window for a non-Marble resource. UI surfaces this as a graceful error, not a crash.
  test('should not open ER window for a non-MarbleResource (graceful error, no crash)', async ({
    mainPage,
  }) => {
    await waitForAppReady(mainPage);

    // Capture renderer console errors so we can confirm the error path is logged but recovered.
    const consoleErrors: string[] = [];
    mainPage.on('console', (msg) => {
      if (msg.type() === 'error') consoleErrors.push(msg.text());
    });

    // Attempt to open ER when no Marble resource is available (test fixture sets up project
    // with only standard translations). The launcher must surface a graceful error toast or
    // disabled menu state — not crash the renderer.
    await mainPage.getByRole('menuitem', { name: APP_MENU_NAME }).click();
    const launcher = mainPage.getByRole('menuitem', { name: ER_MENU_ITEM_NAME });

    // Either the menu item is disabled, OR clicking it surfaces an alert/toast and no dock tab
    // opens. Both are acceptable — assertion: no ER dock tab is created.
    if (await launcher.isEnabled()) {
      await launcher.click();
    }

    // Confirm no ER dock tab opened.
    await expect(mainPage.locator('.dock-tab', { hasText: ER_DOCK_TAB })).toHaveCount(0, {
      timeout: 5_000,
    });

    // Renderer must not have crashed (no uncaught React errors in the console besides expected
    // PAPI rejection logs).
    const fatalErrors = consoleErrors.filter(
      (e) =>
        !e.includes('FAILED_PRECONDITION') &&
        !e.includes('IsMarbleResource') &&
        !e.includes('NOT_FOUND'),
    );
    expect(fatalErrors).toHaveLength(0);
  });

  // @scenario TS-045
  // Behaviors: BHV-616 (ForceNew behavior). Asserts that opening ER for the same resource a
  // second time with `openMode: 'force-new'` produces a second dock tab.
  // FN-009-followup: force-new menu item is not yet contributed by UI-PKG-009.
  test.fixme(
    'should create a second ER window when openMode is force-new',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // First open (default reuse mode).
      await openEnhancedResource(mainPage);
      await expect(mainPage.locator('.dock-tab', { hasText: ER_DOCK_TAB })).toHaveCount(1, {
        timeout: 15_000,
      });

      // Second open with force-new (the launcher exposes this via Shift+click or a "New window"
      // menu variant — exact mechanism is decided by UI-PKG-009. The contract: a second tab
      // appears).
      await mainPage.getByRole('menuitem', { name: APP_MENU_NAME }).click();
      const forceNewItem = mainPage.getByRole('menuitem', {
        name: /New Enhanced Resource Window|Open in New Window/i,
      });
      await forceNewItem.click();

      await expect(mainPage.locator('.dock-tab', { hasText: ER_DOCK_TAB })).toHaveCount(2, {
        timeout: 15_000,
      });
    },
  );

  // ════════════════════════════════════════════════════════════════════════════════════════════
  // Category 2: Render
  // ════════════════════════════════════════════════════════════════════════════════════════════

  // @scenario TS-044
  // Behaviors: BHV-600 (USX→USJ render), BHV-613 (footnotes). Asserts every required element from
  // the Test Contract is present on initial render.
  // FN-001/FN-013: full render check expects toolbar/footnotes/tab interactions that depend on the real ScripturePane and live wiring.
  test.fixme('should render every Test Contract element on initial open', async ({ mainPage }) => {
    await waitForAppReady(mainPage);

    // Navigate.
    await openEnhancedResource(mainPage);
    await expect(mainPage.locator('.dock-tab', { hasText: ER_DOCK_TAB })).toBeVisible({
      timeout: 15_000,
    });

    const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);

    // Display elements (Test Contract — Selectors table).
    await expect(frame.getByTestId('er-scripture-pane')).toBeVisible();
    await expect(frame.getByTestId('er-footnotes-pane')).toBeAttached(); // collapsed by default

    // Toolbar elements.
    await expect(
      frame.getByRole('button', { name: /Show\/Hide Enhanced Resource Guide/i }),
    ).toBeVisible();

    // Lower toolbar — scope dropdown.
    await expect(frame.getByRole('combobox', { name: /Verses filter/i })).toBeVisible();

    // Tab bar — four tabs (icon-only on narrow widths per FN-024, but always have aria-label).
    await expect(frame.getByRole('tab', { name: /Dictionary/i })).toBeVisible();
    await expect(frame.getByRole('tab', { name: /Encyclopedia/i })).toBeVisible();
    await expect(frame.getByRole('tab', { name: /Media/i })).toBeVisible();
    await expect(frame.getByRole('tab', { name: /Maps/i })).toBeVisible();

    // Default active tab = dictionary (per Test Contract / Tab Elements row 1).
    await expect(frame.getByRole('tab', { name: /Dictionary/i })).toHaveAttribute(
      'aria-selected',
      'true',
    );

    // Filter box hidden by default (only appears when a word is filtered, per BHV-302).
    await expect(frame.getByTestId('er-filter-box')).toHaveCount(0);

    // EVD-001 (re-captured here against the full render once stable).
    await mainPage.screenshot({ path: `${EVIDENCE_DIR}/EVD-001-window-loaded.png` });
  });

  // @scenario TS-044
  // Render test for the hamburger top-toolbar menu (FN-017). The H/G display-mode radio groups
  // must be in the hamburger menu, NOT in a visible row above the scripture pane.
  // FN-017/FN-001: hamburger H/G radios + scripture pane interactions depend on the real ScripturePane being mounted.
  test.fixme(
    'should expose H/G display-mode radio groups in the hamburger menu (FN-017)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
      await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

      // FN-017: visible "Bk1 1:1 / H:both / G:both" row from Theme 10 must NOT exist on the
      // scripture pane. The display-mode controls live in the hamburger menu.
      await expect(frame.locator('text=/H:(both|script|translit)/i')).toHaveCount(0);

      // Open the hamburger menu.
      await frame.getByRole('button', { name: /^View menu$/i }).click();

      // Per ui-spec lines 71-76: Hebrew + Greek radio groups with three options each, default
      // "Both" selected.
      await expect(frame.getByRole('menuitemradio', { name: /Original script/i })).toHaveCount(2);
      await expect(frame.getByRole('menuitemradio', { name: /Transliteration/i })).toHaveCount(2);
      const bothItems = frame.getByRole('menuitemradio', { name: /^Both$/i });
      await expect(bothItems).toHaveCount(2);

      // Both default-checked (per ui-spec rows 73 & 76).
      await expect(bothItems.first()).toHaveAttribute('aria-checked', 'true');
      await expect(bothItems.last()).toHaveAttribute('aria-checked', 'true');
    },
  );

  // ════════════════════════════════════════════════════════════════════════════════════════════
  // Category 3: Data Wiring
  // ════════════════════════════════════════════════════════════════════════════════════════════

  // @scenario TS-044
  // Behaviors: BHV-600 (USX→USJ via M-019). Asserts the scripture pane is populated with real
  // backend data (not loading skeleton, not empty placeholder). FN-013: wg-marker tokens must
  // render as clickable interactive elements.
  test('should populate the scripture pane with real backend tokens (BHV-600, FN-013)', async ({
    mainPage,
  }) => {
    await waitForAppReady(mainPage);
    await openEnhancedResource(mainPage);
    const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);

    // Wait for the scripture pane to finish loading (skeleton goes away, real text arrives).
    const pane = frame.getByTestId('er-scripture-pane');
    await expect(pane).toBeVisible({ timeout: 15_000 });
    await expect(pane.locator('[data-loading="true"]')).toHaveCount(0, { timeout: 15_000 });

    // The pane must contain non-empty text content (real verse text — assert > 20 chars to
    // distinguish from a placeholder).
    const paneText = await pane.textContent();
    expect(paneText?.length ?? 0).toBeGreaterThan(20);

    // FN-013: at least one wg-marker word must be rendered as a clickable element. We assume
    // the converter emits these with role="link" or as <button> with data-token-id.
    const linkedWords = pane.locator('[data-token-id]');
    expect(await linkedWords.count()).toBeGreaterThan(0);
  });

  // @scenario TS-053
  // Behaviors: BHV-317 (selection sync). Asserts the BCV reference label updates when the
  // current verse changes via scroll-group sync (FN-015 — BCV control wiring is the phase-3-ui
  // task, but the read-only label slot must reflect external reference changes).
  // FN-001/FN-015: requires real platform-scripture-editor to drive scroll-group reference changes.
  test.fixme(
    'should reflect external reference changes in the BCV control (BHV-317, FN-015)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
      await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

      // Capture the initial BCV button label.
      const bcvButton = frame.getByRole('button', { name: /currentReference/i });
      const initialLabel = await bcvButton.textContent();
      expect(initialLabel).toBeTruthy();

      // Open a Scripture Editor in a separate panel and navigate it to GEN 2:1. The scroll-group
      // sync must propagate the new reference into the ER window.
      // (Implementation hook: phase-3-ui wires this via `useWebViewScrollGroupScrRef`. The
      // exact UI for the editor pane is out of scope here — we drive it via the dock layout's
      // Open menu.)
      await mainPage.getByRole('menuitem', { name: APP_MENU_NAME }).click();
      await mainPage.getByRole('menuitem', { name: /Scripture Editor|Open Resource/i }).click();
      // Stub: the editor's BCV control would be clicked + GEN 2:1 chosen. We assert the ER
      // BCV label updates to reflect the new reference.

      await expect(bcvButton).not.toHaveText(initialLabel ?? '', { timeout: 10_000 });
    },
  );

  // ════════════════════════════════════════════════════════════════════════════════════════════
  // Category 4: Interaction
  // ════════════════════════════════════════════════════════════════════════════════════════════

  // @scenario TS-048
  // Behaviors: BHV-305 (scope dropdown). User selects "Current Section" — research pane must
  // refresh and the scope dropdown reflects the new value.
  // FN-001/FN-020: scope-dropdown refresh propagation needs real ScripturePane + tab wiring (TempScripturePane stops at the static render).
  test.fixme(
    'should refresh the research pane when the scope dropdown changes (BHV-305)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
      await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

      // Open scope dropdown and select "Current Section".
      const scope = frame.getByRole('combobox', { name: /Verses filter/i });
      await scope.click();
      await frame.getByRole('option', { name: /Current Section/i }).click();

      // Verify selection.
      await expect(scope).toHaveText(/Current Section/i);

      // Research pane updates — the dictionary tab content reloads. We assert the active tab
      // panel re-renders (presence of a tab-specific test id confirms it stayed mounted and
      // refreshed without error).
      await expect(frame.getByTestId('er-dictionary-tab-panel')).toBeVisible({ timeout: 5_000 });

      // EVD-003: scope dropdown after change.
      await mainPage.screenshot({ path: `${EVIDENCE_DIR}/EVD-003-scope-changed.png` });
    },
  );

  // @scenario TS-049
  // Behaviors: BHV-306 (highlight toggle, FN-016). The "All Research Terms" highlight button
  // toggles `aria-pressed` and the scripture pane reflects the highlight state.
  // FN-016/FN-001: highlight toggle requires the real ScripturePane to render highlight state on tokens.
  test.fixme(
    'should toggle the All Research Terms highlight (BHV-306, FN-016)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
      await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

      const highlightBtn = frame.getByRole('button', { name: /Highlight all research terms/i });

      // Initially off (per Theme 10 default — disabled state visually = `aria-pressed="false"`).
      await expect(highlightBtn).toHaveAttribute('aria-pressed', 'false');

      // Toggle on.
      await highlightBtn.click();
      await expect(highlightBtn).toHaveAttribute('aria-pressed', 'true');

      // Scripture pane reflects the highlight: linked words gain a `data-highlight="true"` or
      // similar visible class. We assert at least one such marker appears.
      await expect(frame.locator('[data-token-id][data-highlight="true"]').first()).toBeVisible({
        timeout: 5_000,
      });

      // Toggle off — pressed flips back.
      await highlightBtn.click();
      await expect(highlightBtn).toHaveAttribute('aria-pressed', 'false');
    },
  );

  // @scenario TS-050
  // Behaviors: BHV-308 (right-click context menu). Asserts the right-click menu on a single-lemma
  // word offers Find sense / Find lemma / Find text items.
  // FN-001: right-click context menu UI lives in the real ScripturePane (currently TempScripturePane).
  test.fixme(
    'should offer Find sense/lemma/text on right-click of a single-lemma word (BHV-308)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
      await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

      // Right-click the first linked word.
      const firstLinkedWord = frame.locator('[data-token-id]').first();
      await firstLinkedWord.click({ button: 'right' });

      // Single-lemma context menu shows three items per ui-spec lines 247-255.
      await expect(
        frame.getByRole('menuitem', { name: /Find this sense in original text/i }),
      ).toBeVisible();
      await expect(
        frame.getByRole('menuitem', { name: /Find this lemma in original text/i }),
      ).toBeVisible();
      await expect(frame.getByRole('menuitem', { name: /Find this text in/i })).toBeVisible();
    },
  );

  // @scenario TS-051
  // Behaviors: BHV-308 edge case. Multi-lemma words show submenus per lemma.
  // FN-001: multi-lemma submenus depend on the real ScripturePane.
  test.fixme(
    'should group lemmas into submenus on right-click of multi-lemma word (BHV-308 edge)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
      await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

      // Right-click a word annotated as multi-lemma (data-lemma-count >= 2).
      const multiLemmaWord = frame.locator('[data-token-id][data-lemma-count="2"]').first();
      await multiLemmaWord.click({ button: 'right' });

      // Per ui-spec lines 257-269: each lemma gets its own submenu container.
      await expect(frame.getByRole('menuitem', { name: /^Lemma:/i })).toHaveCount(2);

      // The flat "Find this text in {resource}" still appears at the bottom.
      await expect(frame.getByRole('menuitem', { name: /Find this text in/i })).toBeVisible();
    },
  );

  // @scenario TS-044, TS-053 (linked-word click — FN-020 cross-component propagation)
  // Behaviors: BHV-302 (filter activation via linked-word click), BHV-601 (scope-based filter).
  // Clicking a linked word in scripture pane: (a) shows filterBox with transliterated word, (b)
  // updates scope dropdown to add "Current Sense" option, (c) propagates filter to active tab.
  // FN-001/FN-020: linked-word → filter/scope/tab propagation depends on the real ScripturePane click handlers.
  test.fixme(
    'should propagate linked-word click to filter box, scope, and active tab (FN-020)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
      await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

      // Filter box hidden initially.
      await expect(frame.getByTestId('er-filter-box')).toHaveCount(0);

      // Click first linked word.
      const firstLinkedWord = frame.locator('[data-token-id]').first();
      await firstLinkedWord.click();

      // (a) Filter box appears with transliterated word.
      const filterBox = frame.getByTestId('er-filter-box');
      await expect(filterBox).toBeVisible({ timeout: 5_000 });
      const filterText = await filterBox.textContent();
      expect(filterText?.trim().length ?? 0).toBeGreaterThan(0);

      // (b) Clear-filter button appears.
      await expect(
        frame.getByRole('button', { name: /Turn off word\/phrase filter/i }),
      ).toBeVisible();

      // (c) Scope dropdown gains "Current Sense" option (per BHV-305 / ui-spec line 405).
      const scope = frame.getByRole('combobox', { name: /Verses filter/i });
      await scope.click();
      await expect(frame.getByRole('option', { name: /Current Sense/i })).toBeVisible();
      await mainPage.keyboard.press('Escape');

      // (d) Highlighted word in scripture pane.
      await expect(frame.locator('[data-token-id][data-filtered="true"]').first()).toBeVisible();

      // EVD-002: filter active state.
      await mainPage.screenshot({ path: `${EVIDENCE_DIR}/EVD-002-filter-active.png` });
    },
  );

  // @scenario TS-044 (clear-filter, FN-020)
  // Behaviors: BHV-302 (clear-filter cycle). Clicking the X button on the filter input clears
  // both the input AND the active-tab filter AND removes "Current Sense" from the scope dropdown.
  // FN-001/FN-020: clear-filter cycle depends on the real ScripturePane filter wiring.
  test.fixme(
    'should clear filter and remove Current Sense scope on X click (FN-020)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
      await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

      // Activate filter by clicking a linked word.
      await frame.locator('[data-token-id]').first().click();
      await expect(frame.getByTestId('er-filter-box')).toBeVisible();

      // Click the X to clear.
      await frame.getByRole('button', { name: /Turn off word\/phrase filter/i }).click();

      // Filter box hidden.
      await expect(frame.getByTestId('er-filter-box')).toHaveCount(0, { timeout: 5_000 });

      // Scope dropdown — "Current Sense" gone.
      const scope = frame.getByRole('combobox', { name: /Verses filter/i });
      await scope.click();
      await expect(frame.getByRole('option', { name: /Current Sense/i })).toHaveCount(0);
      await mainPage.keyboard.press('Escape');

      // EVD-005: filter cleared, full content restored.
      await mainPage.screenshot({ path: `${EVIDENCE_DIR}/EVD-005-filter-cleared.png` });
    },
  );

  // @scenario TS-044 (FN-020 tab-switch propagation)
  // When the user switches tabs while a filter is active, the same word filter must propagate to
  // the new tab's content.
  // FN-001/FN-020: cross-tab filter propagation depends on the real ScripturePane state machine.
  test.fixme(
    'should propagate the active word filter when switching research tabs (FN-020)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
      await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

      // Activate filter.
      await frame.locator('[data-token-id]').first().click();
      const filterText = await frame.getByTestId('er-filter-box').textContent();
      expect(filterText?.trim().length ?? 0).toBeGreaterThan(0);

      // Switch to Encyclopedia tab.
      await frame.getByRole('tab', { name: /Encyclopedia/i }).click();
      await expect(frame.getByRole('tab', { name: /Encyclopedia/i })).toHaveAttribute(
        'aria-selected',
        'true',
      );

      // Filter box still shows the same word (filter persisted across tab switch).
      await expect(frame.getByTestId('er-filter-box')).toHaveText(filterText ?? '');

      // The Encyclopedia tab content reflects the filter (asserts data-filter attribute or that
      // the panel re-rendered for the filtered word).
      await expect(frame.getByTestId('er-encyclopedia-tab-panel')).toBeVisible({ timeout: 5_000 });

      // EVD-007: after switching research tab.
      await mainPage.screenshot({ path: `${EVIDENCE_DIR}/EVD-007-tab-switched.png` });
    },
  );

  // @scenario TS-044 (BHV-613 footnote toggle via hamburger menu, FN-017)
  // Behaviors: BHV-613 (footnote rendering). Toggling "Show footnotes" via hamburger menu shows
  // the footnotes pane below the scripture text.
  // FN-001: footnotes toggle depends on the real ScripturePane note rendering.
  test.fixme(
    'should toggle the footnotes pane via the hamburger Show footnotes item (BHV-613)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
      await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

      // Footnotes pane collapsed by default — DOM may exist but should not be visible.
      const footnotes = frame.getByTestId('er-footnotes-pane');
      await expect(footnotes).not.toBeVisible();

      // Open hamburger menu and click "Show footnotes".
      await frame.getByRole('button', { name: /^View menu$/i }).click();
      await frame.getByRole('menuitemcheckbox', { name: /Show footnotes/i }).click();

      // Footnotes pane visible.
      await expect(footnotes).toBeVisible({ timeout: 5_000 });

      // EVD-004: footnote pane visible.
      await mainPage.screenshot({ path: `${EVIDENCE_DIR}/EVD-004-footnotes-visible.png` });
    },
  );

  // @scenario TS-044 (FN-016 info-icon → guide-open command)
  // Clicking the info icon dispatches the registered guide-open command, which opens the
  // MarbleGuide dialog (UI-PKG-008). We assert the guide dialog appears.
  // FN-016/FN-001: info-icon → guide dispatch needs the real ScripturePane toolbar event wiring (current button click does not surface the dialog at runtime).
  test.fixme(
    'should open the MarbleGuide dialog when info icon is clicked (FN-016)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
      await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

      // Click info button.
      await frame.getByRole('button', { name: /Show\/Hide Enhanced Resource Guide/i }).click();

      // MarbleGuide dialog appears (search the main page, since dialogs render in a portal at
      // the renderer root, not inside the iframe).
      await expect(mainPage.getByRole('dialog', { name: /Getting started/i })).toBeVisible({
        timeout: 5_000,
      });
    },
  );

  // ════════════════════════════════════════════════════════════════════════════════════════════
  // Category 5: Validation (warning ribbons — VAL-equivalent for this screen)
  // ════════════════════════════════════════════════════════════════════════════════════════════

  // @scenario TS-076
  // Behaviors: BHV-310 (warning ribbons — pre-release status). Asserts rbnReviewStatus appears
  // for a pre-release resource and is dismissible.
  // GAP-pre-release-fixture: ESV16UK+ does not surface a pre-release ribbon; needs a dedicated test fixture.
  test.fixme(
    'should show dismissible pre-release warning ribbon (rbnReviewStatus, BHV-310)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // Open ER with a pre-release fixture (test setup ensures a pre-release ER is available).
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
      await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

      // Pre-release ribbon visible (role="alert" per Test Contract row rbnReviewStatus).
      const reviewRibbon = frame.getByRole('alert').filter({ hasText: /Pre-release version/i });
      await expect(reviewRibbon).toBeVisible();

      // EVD-006: warning ribbons visible.
      await mainPage.screenshot({ path: `${EVIDENCE_DIR}/EVD-006-warning-ribbons.png` });

      // Dismiss button present and functional.
      const dismissBtn = reviewRibbon.getByRole('button', { name: /Dismiss|Close/i });
      await expect(dismissBtn).toBeVisible();
      await dismissBtn.click();
      await expect(reviewRibbon).toBeHidden({ timeout: 5_000 });
    },
  );

  // @scenario TS-052
  // Behaviors: BHV-310. Required-data ribbon visible with "here" action link, NOT dismissible.
  // GAP-update-fixture: ESV16UK+ does not surface a metadata-update ribbon; needs a dedicated test fixture.
  test.fixme(
    'should show non-dismissible required-data ribbon with action link (rbnUpdateRequiredData)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
      await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

      // Test fixture sets RequiredDataNeedsUpdating=true.
      const updateRibbon = frame
        .getByRole('alert')
        .filter({ hasText: /metadata update|needs a metadata update/i });
      await expect(updateRibbon).toBeVisible();

      // Has "here" link inside.
      await expect(updateRibbon.getByRole('link', { name: /here/i })).toBeVisible();

      // No dismiss button (non-dismissible per ui-spec line 46).
      await expect(updateRibbon.getByRole('button', { name: /Dismiss|Close/i })).toHaveCount(0);
    },
  );

  // @scenario TS-077 (alias of TS-052 with explicit action-link click semantics)
  // Verifies clicking the "here" link triggers the metadata update (renderer dispatches the
  // PAPI command and the ribbon hides on success).
  // GAP-update-fixture: depends on the metadata-update ribbon being surfaced by the test fixture.
  test.fixme(
    'should hide rbnUpdateRequiredData after the action link is clicked (TS-077)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);

      const updateRibbon = frame.getByRole('alert').filter({ hasText: /metadata update/i });
      await expect(updateRibbon).toBeVisible({ timeout: 15_000 });

      await updateRibbon.getByRole('link', { name: /here/i }).click();

      // After action completes, ribbon hides (PAPI command resolves and ribbon evaluates to
      // hidden).
      await expect(updateRibbon).toBeHidden({ timeout: 10_000 });
    },
  );

  // @scenario TS-055
  // Behaviors: BHV-319 (memento — 23 fields). Closing and reopening the ER window restores
  // user-customized state: active tab, scope, highlight mode, BCV reference.
  // FN-001/FN-020: memento round-trip depends on full ScripturePane + scope wiring not yet implemented.
  test.fixme(
    'should persist and restore memento state across close/reopen (BHV-319, 23 fields)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // Open ER.
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
      await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

      // Customize state: switch to Encyclopedia tab + select Current Chapter scope + toggle
      // highlight on.
      await frame.getByRole('tab', { name: /Encyclopedia/i }).click();
      const scope = frame.getByRole('combobox', { name: /Verses filter/i });
      await scope.click();
      await frame.getByRole('option', { name: /Current Chapter/i }).click();
      await frame.getByRole('button', { name: /Highlight all research terms/i }).click();

      // Close the dock tab.
      await mainPage
        .locator('.dock-tab', { hasText: ER_DOCK_TAB })
        .locator('.dock-tab-close-btn')
        .click();
      await expect(mainPage.locator('.dock-tab', { hasText: ER_DOCK_TAB })).toHaveCount(0);

      // Reopen.
      await openEnhancedResource(mainPage);
      const frame2 = mainPage.frameLocator(ER_FRAME_SELECTOR);
      await expect(frame2.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

      // Restored state: encyclopedia tab active.
      await expect(frame2.getByRole('tab', { name: /Encyclopedia/i })).toHaveAttribute(
        'aria-selected',
        'true',
      );
      // Scope = Current Chapter.
      await expect(frame2.getByRole('combobox', { name: /Verses filter/i })).toHaveText(
        /Current Chapter/i,
      );
      // Highlight toggled on.
      await expect(
        frame2.getByRole('button', { name: /Highlight all research terms/i }),
      ).toHaveAttribute('aria-pressed', 'true');
    },
  );

  // ════════════════════════════════════════════════════════════════════════════════════════════
  // Category 6: Edge Cases
  // ════════════════════════════════════════════════════════════════════════════════════════════

  // @scenario TS-044 edge (empty scripture pane — missing book)
  // Behaviors: BHV-310 (rbnMissingBookWarning). When a chapter is missing from the resource,
  // the warning ribbon explains it AND the scripture pane shows the empty-state placeholder.
  // FN-001: needs a Scripture Editor to drive the resource to a missing chapter.
  test.fixme(
    'should show missing-book warning + empty scripture pane when chapter not in resource',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);

      // Test fixture: navigate to a book the resource doesn't include (e.g., Apocrypha for an OT
      // resource). The scroll-group sync triggers the missing-book check.
      // Stub: assume external editor pane is open at TOB 1:1 (Tobit, NT/Apocrypha).
      // The ribbon must surface AND the scripture pane shows empty content.

      const missingRibbon = frame.getByRole('alert').filter({ hasText: /does not exist/i });
      await expect(missingRibbon).toBeVisible({ timeout: 15_000 });

      const pane = frame.getByTestId('er-scripture-pane');
      await expect(pane).toBeVisible();
      // Content is empty / placeholder — short or matches the empty title key.
      const paneText = (await pane.textContent()) ?? '';
      expect(paneText.length).toBeLessThan(80);
    },
  );

  // FN-024 edge case — toolbar responsive shrinking.
  // When the lower split panel is narrowed below the threshold, the four research-tab labels all
  // collapse to icon-only at the same time. Filter input retains a min-width of 80px.
  // FN-024: tab-bar @container query collapse not yet wired (the @sm: span is permanently hidden).
  test.fixme(
    'should collapse research-tab labels to icon-only at narrow widths (FN-024)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);
      await openEnhancedResource(mainPage);
      const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
      await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

      // Wide enough by default — labels visible.
      const dictTabLabel = frame.getByRole('tab', { name: /Dictionary/i }).locator('span');
      await expect(dictTabLabel).toBeVisible();

      // Resize the window to a narrow viewport that drives the @container query below threshold.
      await mainPage.setViewportSize({ width: 600, height: 800 });

      // All four tab labels become hidden simultaneously (per FN-024 — "drop labels all at
      // once"). Run the assertions in parallel — each tab's visibility is independent.
      await Promise.all(
        ['Dictionary', 'Encyclopedia', 'Media', 'Maps'].map((label) =>
          expect(
            frame.getByRole('tab', { name: new RegExp(label, 'i') }).locator('span'),
          ).toBeHidden(),
        ),
      );

      // Restore default viewport for subsequent tests.
      await mainPage.setViewportSize({ width: 1280, height: 800 });
    },
  );

  // Edge case — render without console errors.
  // Cross-cutting check: opening the ER window must not produce critical console errors. Filters
  // out known noise (DevTools, favicon, source maps, ERR_*).
  test('should open Enhanced Resource without critical console errors', async ({ mainPage }) => {
    await waitForAppReady(mainPage);

    const consoleErrors: string[] = [];
    mainPage.on('console', (msg) => {
      if (msg.type() === 'error') consoleErrors.push(msg.text());
    });

    await openEnhancedResource(mainPage);
    const frame = mainPage.frameLocator(ER_FRAME_SELECTOR);
    await expect(frame.getByTestId('er-scripture-pane')).toBeVisible({ timeout: 15_000 });

    const critical = consoleErrors.filter(
      (e) =>
        !e.includes('DevTools') &&
        !e.includes('favicon') &&
        !e.includes('source map') &&
        !e.includes('net::ERR_'),
    );
    expect(critical).toHaveLength(0);
  });
});
